        }

        setContentView(createContentView())
        setupBiometric()
        setupUi()

        maybeStartBiometric()
    }

    private fun setupUi() {
        btnBiometric.setOnClickListener {
            if (canUseBiometrics()) {
                tvStatus.text = "Authenticate with fingerprint"
                biometricPrompt.authenticate(promptInfo)
            } else {
                tvStatus.text = "Biometric not available. Use password."
                showPasswordFallbackDialog()
            }
        }

        btnPassword.setOnClickListener {
            showPasswordFallbackDialog()
        }
    }

    private fun maybeStartBiometric() {
        if (canUseBiometrics()) {
            tvStatus.text = "Authenticate with fingerprint"
            biometricPrompt.authenticate(promptInfo)
        } else {
            tvStatus.text = "Use password to continue"
        }
    }

    private fun canUseBiometrics(): Boolean {
        val manager = BiometricManager.from(this)
        val authenticators = BiometricManager.Authenticators.BIOMETRIC_STRONG or
            BiometricManager.Authenticators.BIOMETRIC_WEAK
        return manager.canAuthenticate(authenticators) == BiometricManager.BIOMETRIC_SUCCESS
    }

    private fun setupBiometric() {
        val executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(
            this,
            executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    onAuthenticated()
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    tvStatus.text = errString
                    if (errorCode == BiometricPrompt.ERROR_NEGATIVE_BUTTON ||
                        errorCode == BiometricPrompt.ERROR_USER_CANCELED ||
                        errorCode == BiometricPrompt.ERROR_CANCELED
                    ) {
                        showPasswordFallbackDialog()
                    } else {
                        showPasswordFallbackDialog()
                    }
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    tvStatus.text = "Fingerprint not recognized. Try again or use password."
                }
            }
        )

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Sign in")
            .setSubtitle("Use your fingerprint to continue")
            .setDescription("Quick and secure authentication")
            .setNegativeButtonText("Use password")
            .build()
    }

    private fun onAuthenticated() {
        AuthPrefs.setAuthenticated(this, true)
