        val title = TextView(this).apply {
            text = "Login"
            textSize = 22f
        }

        tvStatus = TextView(this).apply {
            text = "Authenticate to continue"
            textSize = 14f
            setPadding(0, dp(10), 0, dp(18))
        }

        btnBiometric = Button(this).apply {
            text = "Use fingerprint"
        }

        btnPassword = Button(this).apply {
            text = "Use password"
        }

